(() => {
  const bridge = window.__JONES_FASTLANE_SESSION__;
  const raw = bridge?.getState?.() ?? JSON.parse(localStorage.getItem(\"jones_fastlane_save\") || \"null\");
  const g = raw?.gameState || raw;
  const p = g?.player || {};
  const s = g?.stats || p?.stats || {};
  const summary = g?.pendingTurnSummary || null;
  const trauma = (g?.effects || p?.effects || []).find?.(e => /TRAUMA_REBOOT/i.test(e?.id || e?.type || e?.name || \"\")) || null;
  return JSON.stringify({
    screen: g?.screen || raw?.screen || null,
    week: g?.week ?? g?.time?.week ?? null,
    day: g?.day ?? g?.time?.day ?? null,
    credits: p?.credits ?? s?.credits ?? null,
    debt: p?.debt ?? s?.debt ?? null,
    hunger: p?.hunger ?? s?.hunger ?? null,
    sanity: p?.sanity ?? s?.sanity ?? null,
    traumaHours: trauma?.durationHours ?? trauma?.hoursRemaining ?? trauma?.remainingHours ?? null,
    hasPendingTurnSummary: "'!!summary,
    summaryPhase: summary?.phase ?? null,
    browserStateSource: bridge ? "live_session" : (localStorage.getItem("jones_fastlane_save") ? "local_storage" : "none")
  }, null, 2);
})()'"'"

